import{_ as a,c as t,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const v=JSON.parse(`{"title":"Fonctionnalités de plateforme: Révision de plans et de code | Plannotator","description":"Découvrez les fonctionnalités de plateforme de Plannotator, incluant la révision de plans et la révision de code. Maîtrisez les compétences essentielles: révision visuelle, ajout d'annotations et marquage d'images.","frontmatter":{"title":"Fonctionnalités de plateforme: Révision de plans et de code | Plannotator","sidebarTitle":"Révision de plans et de code IA","subtitle":"Fonctionnalités de plateforme: Révision de plans et de code","description":"Découvrez les fonctionnalités de plateforme de Plannotator, incluant la révision de plans et la révision de code. Maîtrisez les compétences essentielles: révision visuelle, ajout d'annotations et marquage d'images.","order":2},"headers":[],"relativePath":"fr/backnotprop/plannotator/platforms/index.md","filePath":"fr/backnotprop/plannotator/platforms/index.md"}`),s={name:"fr/backnotprop/plannotator/platforms/index.md"};function o(r,e,d,l,p,c){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="fonctionnalites-de-plateforme" tabindex="-1">Fonctionnalités de plateforme <a class="header-anchor" href="#fonctionnalites-de-plateforme" aria-label="Permalink to &quot;Fonctionnalités de plateforme&quot;">​</a></h1><p>Ce chapitre présente les deux fonctionnalités principales de Plannotator : la <strong>révision de plans</strong> et la <strong>révision de code</strong>. Vous apprendrez à réviser visuellement les plans générés par l&#39;IA, à ajouter différents types d&#39;annotations, à joindre des marquages d&#39;images, ainsi qu&#39;à réviser les modifications de code via git diff.</p><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Vérifiez avant de commencer</p><p>Avant d&#39;aborder ce chapitre, assurez-vous d&#39;avoir complété les étapes suivantes :</p><ul><li>✅ Avoir terminé le tutoriel <a href="./../start/getting-started/">Démarrage rapide</a></li><li>✅ Avoir installé le plugin Plannotator (<a href="./../start/installation-claude-code/">Claude Code</a> ou <a href="./../start/installation-opencode/">OpenCode</a>)</li></ul></div><h2 id="contenu-du-chapitre" tabindex="-1">Contenu du chapitre <a class="header-anchor" href="#contenu-du-chapitre" aria-label="Permalink to &quot;Contenu du chapitre&quot;">​</a></h2><h3 id="revision-de-plans" tabindex="-1">Révision de plans <a class="header-anchor" href="#revision-de-plans" aria-label="Permalink to &quot;Révision de plans&quot;">​</a></h3><p>Apprenez à réviser les plans d&#39;exécution générés par l&#39;IA, à ajouter des suggestions de modification pour que l&#39;IA exécute selon vos intentions.</p><table tabindex="0"><thead><tr><th>Tutoriel</th><th>Description</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">Bases de la révision de plans</a></td><td>Apprenez à utiliser Plannotator pour réviser visuellement les plans générés par l&#39;IA, y compris l&#39;approbation ou le rejet de plans</td></tr><tr><td><a href="./plan-review-annotations/">Ajout d&#39;annotations de plan</a></td><td>Maîtrisez l&#39;ajout de différents types d&#39;annotations dans les plans (suppression, remplacement, insertion, commentaire)</td></tr><tr><td><a href="./plan-review-images/">Ajout de marquages d&#39;images</a></td><td>Apprenez à joindre des images lors de la révision de plans et à utiliser les outils pinceau, flèche et cercle pour les annoter</td></tr></tbody></table><h3 id="revision-de-code" tabindex="-1">Révision de code <a class="header-anchor" href="#revision-de-code" aria-label="Permalink to &quot;Révision de code&quot;">​</a></h3><p>Apprenez à réviser les modifications de code, à ajouter des annotations au niveau des lignes et à détecter les problèmes avant la validation.</p><table tabindex="0"><thead><tr><th>Tutoriel</th><th>Description</th></tr></thead><tbody><tr><td><a href="./code-review-annotations/">Ajout d&#39;annotations de code</a></td><td>Maîtrisez l&#39;ajout d&#39;annotations au niveau des lignes lors de la révision de code (comment/suggestion/concern)</td></tr><tr><td><a href="./code-review-diff-types/">Changement de vue Diff</a></td><td>Apprenez à basculer entre différents types de diff lors de la révision de code (uncommitted/staged/last commit/branch)</td></tr></tbody></table><h2 id="parcours-d-apprentissage" tabindex="-1">Parcours d&#39;apprentissage <a class="header-anchor" href="#parcours-d-apprentissage" aria-label="Permalink to &quot;Parcours d&#39;apprentissage&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Ordre d&#39;apprentissage recommandé</p><p>Selon votre cas d&#39;utilisation, choisissez le parcours d&#39;apprentissage approprié :</p><p><strong>Parcours A : Révision de plans en priorité</strong> (recommandé pour les débutants)</p><ol><li><a href="./plan-review-basics/">Bases de la révision de plans</a> → Commencez par maîtriser le processus de base de révision de plans</li><li><a href="./plan-review-annotations/">Ajout d&#39;annotations de plan</a> → Apprenez à modifier les plans avec précision</li><li><a href="./plan-review-images/">Ajout de marquages d&#39;images</a> → Exprimez vos intentions plus clairement avec des images</li><li>Puis passez à la série sur la révision de code</li></ol><p><strong>Parcours B : Révision de code en priorité</strong> (adapté aux développeurs expérimentés en Code Review)</p><ol><li><a href="./code-review-basics/">Bases de la révision de code</a> → Familiarisez-vous avec l&#39;interface de révision de code</li><li><a href="./code-review-annotations/">Ajout d&#39;annotations de code</a> → Apprenez les annotations au niveau des lignes</li><li><a href="./code-review-diff-types/">Changement de vue Diff</a> → Maîtrisez les différents types de diff</li><li>Puis passez à la série sur la révision de plans</li></ol></div><h2 id="etapes-suivantes" tabindex="-1">Étapes suivantes <a class="header-anchor" href="#etapes-suivantes" aria-label="Permalink to &quot;Étapes suivantes&quot;">​</a></h2><p>Après avoir terminé ce chapitre, vous pouvez continuer avec :</p><ul><li><a href="./../advanced/url-sharing/">Partage par URL</a> - Partagez des plans et annotations via URL pour la collaboration en équipe</li><li><a href="./../advanced/obsidian-integration/">Intégration Obsidian</a> - Sauvegardez automatiquement les plans approuvés dans Obsidian</li><li><a href="./../advanced/remote-mode/">Mode distant</a> - Utilisez Plannotator dans des environnements SSH, devcontainer ou WSL</li></ul>',16)])])}const m=a(s,[["render",o]]);export{v as __pageData,m as default};
